// Reference: 4-way round-robin arbiter (rotating priority pointer).
// Contract Phi (see property_tb.v): P1 mutex, P2 no-empty-grant, P3 fairness.
// After serving line g, the base priority rotates to g+1 so every held request
// is granted within N+2 cycles.
module arbiter_rr (
    input            clk,
    input            rst_n,
    input      [3:0] req,
    output reg [3:0] grant
);
    reg [1:0] base;              // lowest-priority-first rotating pointer

    integer   i;
    reg [1:0] cand;             // candidate line examined this iteration
    reg [1:0] gidx;             // line actually granted (latched)
    reg       found;

    // combinational grant: first requesting line at or after `base`, wrapping
    always @(*) begin
        grant = 4'b0000;
        found = 1'b0;
        gidx  = base;
        for (i = 0; i < 4; i = i + 1) begin
            cand = base + i[1:0];        // 2-bit wrap-around
            if (!found && req[cand]) begin
                grant = 4'b0001 << cand;
                gidx  = cand;            // remember who was served
                found = 1'b1;
            end
        end
    end

    // rotate the base to just past whoever was granted
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            base <= 2'd0;
        else if (found)
            base <= gidx + 2'd1;         // rotation: next cycle starts after served line
    end
endmodule

// Valid alternative (§4.2): a rotating-token arbiter, structurally unlike the
// rotating-pointer reference. A token advances one line every cycle and a line
// is granted only while it holds the token and is requesting. This satisfies all
// three properties — mutex (one grant), no-empty-grant (grant only on request),
// and fairness (the token visits every line within N cycles < FAIR_BOUND) — so
// L1 passes and, with no differential harness on this objective, the backbone
// returns ACC. It demonstrates P4: a legitimate alternative is accepted despite
// differing from the reference in both structure and exact grant timing.
module arbiter_rr (
    input            clk,
    input            rst_n,
    input      [3:0] req,
    output reg [3:0] grant
);
    reg [1:0] token;            // which line currently holds the token

    always @(*) begin
        grant = 4'b0000;
        if (req[token])
            grant = 4'b0001 << token;   // serve the token holder iff it requests
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            token <= 2'd0;
        else
            token <= token + 2'd1;      // advance every cycle -> visits all in N
    end
endmodule

// Buggy submission (corpus running example, §4.2): the priority pointer fails to
// rotate past the served line — `base <= gidx` instead of `base <= gidx + 1`.
// It keeps the just-served requester at highest priority, so under held requests
// (e.g. req = 0101) a lower line starves. Compiles (L0 ok), satisfies P1 and P2,
// but L1 emits REJ with a fairness/starvation diagnosis.
module arbiter_rr (
    input            clk,
    input            rst_n,
    input      [3:0] req,
    output reg [3:0] grant
);
    reg [1:0] base;
    integer   i;
    reg [1:0] cand;
    reg [1:0] gidx;
    reg       found;

    always @(*) begin
        grant = 4'b0000;
        found = 1'b0;
        gidx  = base;
        for (i = 0; i < 4; i = i + 1) begin
            cand = base + i[1:0];
            if (!found && req[cand]) begin
                grant = 4'b0001 << cand;
                gidx  = cand;
                found = 1'b1;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
